code = """import json
import re

# Load both datasets
with open(locals()['var_functions.query_db:0'], 'r') as f:
    funding = json.load(f)

with open(locals()['var_functions.query_db:16'], 'r') as f:
    docs = json.load(f)

# Extract all FEMA/emergency projects from funding data
fema_projects = []
for rec in funding:
    proj_name = rec.get('Project_Name', '')
    if 'FEMA' in proj_name.upper() or 'EMERGENCY' in proj_name.upper():
        fema_projects.append({
            'name': proj_name,
            'source': rec.get('Funding_Source'),
            'amount': int(rec.get('Amount', 0))
        })

# Build a comprehensive status map by scanning all documents
status_map = {}
all_text = ' '.join([doc.get('text', '') for doc in docs])

for proj in fema_projects:
    proj_name = proj['name']
    # Get base name without FEMA suffixes
    base_name = proj_name.split(' (')[0]
    
    status = 'Unknown'
    
    # Look for this specific project in the documents
    for doc in docs:
        text = doc.get('text', '')
        if base_name in text:
            # Find the section containing this project
            sections = re.split(r'\n\s*\n', text)
            for section in sections:
                if base_name in section:
                    # Look for Updates: field
                    updates_match = re.search(r'Updates?:(.*?)(?:\n|$)', section, re.IGNORECASE | re.DOTALL)
                    if updates_match:
                        updates_text = updates_match.group(1).strip()
                        
                        # Determine status based on keywords
                        if re.search(r'completed|notice of completion|construction was completed', updates_text, re.IGNORECASE):
                            status = 'completed'
                        elif re.search(r'under construction|construction[^\n]*begin|project is currently under construction', updates_text, re.IGNORECASE):
                            status = 'construction'
                        elif re.search(r'design[^\n]*complete|finalize design|working with consultant|design plans', updates_text, re.IGNORECASE):
                            status = 'design'
                        elif re.search(r'not started|future|identified in', updates_text, re.IGNORECASE):
                            status = 'not started'
                        elif 'advertise' in updates_text.lower() or 'bids' in updates_text.lower():
                            status = 'bidding'
                        break
    
    status_map[proj_name] = status

# Build final results
results = []
for proj in fema_projects:
    results.append({
        'Project_Name': proj['name'],
        'Funding_Source': proj['source'],
        'Amount': proj['amount'],
        'Status': status_map[proj['name']]
    })

# Sort by amount descending
results.sort(key=lambda x: x['Amount'], reverse=True)

print('__RESULT__:')
print(json.dumps(results))"""

